def caesar_cipher(text: str, shift: int) -> str:
    result = ''
    for char in text:
        if char.isalpha():
            if char.islower():
                base = ord('a')
            else:
                base = ord('A')
            result += chr((ord(char) - base + shift) % 26 + base)
        else:
            result += char
    return result
